CREATE OR REPLACE FUNCTION pg6502.reset()
RETURNS VOID AS $$
DECLARE
    v_start_addr INT;
BEGIN
    v_start_addr := pg6502.mem_read16(65532);

    UPDATE pg6502.cpu SET
        a      = 0,
        x      = 0,
        y      = 0,
        sp     = 255,
        pc     = v_start_addr,
        flag_n = FALSE,
        flag_v = FALSE,
        flag_b = FALSE,
        flag_d = FALSE,
        flag_i = TRUE,
        flag_z = FALSE,
        flag_c = FALSE;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION pg6502.run(p_max_cycles INT DEFAULT 100000, p_log_interval INT DEFAULT 1000000)
RETURNS INT AS $$
DECLARE
    v_result TEXT;
    v_cycles INT := 0;
    v_pc INT;
BEGIN
    LOOP
        v_result := pg6502.execute_instruction();
        v_cycles := v_cycles + 1;

        IF v_cycles % p_log_interval = 0 THEN
            SELECT pc INTO v_pc FROM pg6502.cpu;
            RAISE NOTICE 'Cycles: %, PC: %', v_cycles, v_pc;
        END IF;

        EXIT WHEN v_result = 'BRK';
        EXIT WHEN v_cycles >= p_max_cycles;
    END LOOP;

    RETURN v_cycles;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION pg_truncate_larger_tables(
    size INTEGER
) RETURNS BOOL AS $$
DECLARE
    size        ALIAS FOR $1;
    records     RECORD;
    consulta    TEXT;
    execution   TEXT;

BEGIN

    consulta := 'SELECT * FROM (' ||
                'SELECT ' ||
                    'relpages as tretre,
                    relname AS objectname,
                    relkind AS objecttype,
                    reltuples AS "#entries", pg_size_pretty(relpages::bigint*8*1024) AS size
                FROM pg_class
                WHERE relpages >= '||size||'
                ORDER BY ' ||
                'relpages DESC' ||
    ') AS CV;';

    FOR records IN EXECUTE consulta LOOP
        execution := 'TRUNCATE ' || records.objectname || ' CASCADE';
        IF records.objecttype = 'r' AND records.objectname <> 'pg_largeobject' THEN
            EXECUTE execution;
		   RAISE NOTICE 'removing table: % size: %', records.objectname, records.size;
        END IF;
    END LOOP;
    RETURN TRUE;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION
  hdb_catalog.insert_event_log(schema_name text, table_name text, trigger_name text, op text, row_data json)
  RETURNS text AS $$
  DECLARE
  id text;
  payload json;
  session_variables json;
  server_version_num int;
BEGIN
  id := gen_random_uuid();
  server_version_num := current_setting('server_version_num');
  IF server_version_num >= 90600 THEN
    session_variables := current_setting('hasura.user', 't');
  ELSE
    BEGIN
      session_variables := current_setting('hasura.user');
    EXCEPTION WHEN OTHERS THEN
      session_variables := NULL;
    END;
  END IF;
  payload := json_build_object(
    'op', op,
    'data', row_data,
    'session_variables', session_variables
  );
  INSERT INTO hdb_catalog.event_log
    (id, schema_name, table_name, trigger_name, payload)
  VALUES
    (id, schema_name, table_name, trigger_name, payload);
  RETURN id;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION pg_show_larger_object(
    size INTEGER
) RETURNS TEXT AS $$
DECLARE
    size        ALIAS FOR $1;
    records     RECORD;
    queryString TEXT;
	returnData  TEXT DEFAULT '';

BEGIN
    queryString := ''||
		'SELECT ' ||
			'cast(relpages as text),
			relname,
			relkind,
			cast(reltuples as text),
			pg_size_pretty(relpages::bigint*8*1024) AS size
		FROM pg_class
		WHERE
			relpages >= '||size||'
		ORDER BY ' ||
			'relpages DESC';

    FOR records IN EXECUTE queryString LOOP

    	returnData := returnData || ''||
    		'Object: '|| rpad(records.relname, 60, ' ') ||
           	' | Type: ' || rpad(records.relkind, 2, ' ') ||
           	' | Entries: ' || rpad(records.reltuples, 15, ' ') ||
           	' | Pages: '|| rpad(records.relpages, 10, ' ') ||
           	' | Size: ' || rpad(records.size, 12, ' ') || '\n';
    END LOOP;
    RETURN returnData;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION HTTP_POST_XML(
_URL text,
_Username text,
_Password text,
_XML xml
) RETURNS xml AS $BODY$
use strict;
use warnings;
use WWW::Curl::Easy;

my ($url,$username,$password,$xml) = @_;

my $ch = new WWW::Curl::Easy;
$ch->setopt(CURLOPT_HEADER,0);
$ch->setopt(CURLOPT_URL, $url);
$ch->setopt(CURLOPT_USERNAME,$username);
$ch->setopt(CURLOPT_PASSWORD,$password);
$ch->setopt(CURLOPT_POST,1);
$ch->setopt(CURLOPT_NOPROGRESS,0);
$ch->setopt(CURLOPT_POSTFIELDS,$xml);
$ch->setopt(CURLOPT_SSL_VERIFYPEER,1);
$ch->setopt(CURLOPT_SSL_VERIFYHOST,2);

my $response_body;

open (my $fileb, ">", \$response_body);
$ch->setopt(CURLOPT_WRITEDATA,$fileb);

my $retcode = $ch->perform;

if ($retcode == 0) {
    my $response_code = $ch->getinfo(CURLINFO_HTTP_CODE);
} else {
    my $curlerrortext = $ch->strerror($retcode);
    die "ERROR_HTTP_POST_XML CURL_ERROR retcode: $retcode curlerrortext: $curlerrortext";
}

return $response_body;
$BODY$ LANGUAGE plperlu;

CREATE FUNCTION pg_catalog.fix_pre_citus10_partitioned_table_constraint_names(table_name regclass)
  RETURNS void
  LANGUAGE C STRICT
  AS 'MODULE_PATHNAME', $$fix_pre_citus10_partitioned_table_constraint_names$$;
COMMENT ON FUNCTION pg_catalog.fix_pre_citus10_partitioned_table_constraint_names(table_name regclass)
  IS 'fix constraint names on partition shards';

CREATE OR REPLACE FUNCTION pg_catalog.fix_pre_citus10_partitioned_table_constraint_names()
  RETURNS SETOF regclass
  LANGUAGE plpgsql
  SET search_path = pg_catalog, pg_temp
  AS $$
DECLARE
	oid regclass;
BEGIN
    FOR oid IN SELECT c.oid
            FROM pg_dist_partition p
            JOIN pg_class c ON p.logicalrelid = c.oid
			JOIN pg_namespace n ON c.relnamespace = n.oid
        WHERE c.relkind = 'p'
		ORDER BY n.nspname, c.relname
    LOOP
        EXECUTE 'SELECT fix_pre_citus10_partitioned_table_constraint_names( ' || quote_literal(oid) || ' )';
        RETURN NEXT oid;
    END LOOP;
    RETURN;
END;
$$;
COMMENT ON FUNCTION pg_catalog.fix_pre_citus10_partitioned_table_constraint_names()
  IS 'fix constraint names on all partition shards';

